<?php
declare(strict_types=1);
if($path!=='/admin/logs')return;
if(!(user()['is_admin']??false)){http_response_code(403);exit('Forbidden');}
if($method==='POST'){verify_csrf();$days=max(1,min(3650,(int)post('days')));$stmt=db()->prepare('DELETE FROM application_logs WHERE created_at<DATE_SUB(NOW(),INTERVAL ? DAY)');$stmt->execute([$days]);$deleted=$stmt->rowCount();audit('delete_old','application_log',null,['days'=>$days,'deleted'=>$deleted]);flash('success',$deleted.' application log '.($deleted===1?'entry':'entries').' deleted.');redirect('/admin/logs');}
$level=in_array($_GET['level']??'',['debug','info','warning','error'],true)?$_GET['level']:'';$search=trim((string)($_GET['q']??''));$where=['1=1'];$params=[];if($level!==''){$where[]='l.level=?';$params[]=$level;}if($search!==''){$where[]='(l.message LIKE ? OR l.context_json LIKE ?)';$params[]='%'.$search.'%';$params[]='%'.$search.'%';}$stmt=db()->prepare("SELECT l.*,COALESCE(u.username,'System') actor FROM application_logs l LEFT JOIN users u ON u.id=l.user_id WHERE ".implode(' AND ',$where).' ORDER BY l.created_at DESC LIMIT 2000');$stmt->execute($params);$rows=$stmt->fetchAll();
layout('Application logs',function()use($rows,$level,$search){?><div class="actions"><h1 style="margin:0">Application logs</h1><span class="spacer"></span><a class="btn secondary" href="/admin/settings">Application settings</a></div><div class="grid"><form class="card" method="get"><h2>Find log entries</h2><label>Level<select name="level"><option value="">All levels</option><?php foreach(['debug','info','warning','error'] as $option):?><option value="<?=$option?>" <?=$level===$option?'selected':''?>><?=e(ucfirst($option))?></option><?php endforeach?></select></label><label>Message or context contains<input name="q" value="<?=e($search)?>"></label><div class="actions"><button>Apply filters</button><a class="btn secondary" href="/admin/logs">Clear</a></div></form><form class="card" method="post" onsubmit="return confirm('Delete application logs older than the selected number of days?')"><input type="hidden" name="_csrf" value="<?=csrf()?>"><h2>Log retention</h2><p class="muted">This cleans operational logs only. Audit history is not deleted.</p><label>Delete entries older than<input type="number" name="days" min="1" max="3650" value="90" required></label><button class="danger">Delete old logs</button></form></div><div class="card"><div class="actions"><h2 style="margin:0">Entries</h2><span class="spacer"></span><span class="muted"><?=count($rows)?> records<?=count($rows)===2000?' (limit reached)':''?></span></div><div style="overflow:auto"><table><thead><tr><th>When</th><th>Level</th><th>Actor</th><th>Message</th><th>IP address</th><th>Context</th></tr></thead><tbody><?php foreach($rows as $row):?><tr><td><?=e($row['created_at'])?></td><td><span class="log-level log-<?=e($row['level'])?>"><?=e(strtoupper($row['level']))?></span></td><td><?=e($row['actor'])?></td><td><?=e($row['message'])?></td><td><?=e($row['ip_address'])?></td><td><code><?=e(mb_strimwidth((string)$row['context_json'],0,220,'…'))?></code></td></tr><?php endforeach?></tbody></table></div></div><?php });exit;
